// Issue the Building Permit Certificate step component — generated by flowforge JTBD generator.
// Re-run the generator to regenerate; do not edit by hand.
import * as React from "react";

export interface PermitIssuanceStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
}

const FIELDS: ReadonlyArray<{ id: string; label: string; required: boolean; pii: boolean }> = [
	{ id: "permit_number", label: "Permit Number", required: true, pii: false },
	{ id: "issued_date", label: "Issued Date", required: true, pii: false },
	{ id: "clerk_signature", label: "Clerk Signature", required: true, pii: false },
	{ id: "fee_amount", label: "Total Fee Collected", required: true, pii: false },
	{ id: "receipt_number", label: "Payment Receipt Number", required: true, pii: false },
];

/**
 * Minimal review step for the permit_issuance workflow. Hosts wrap this with
 * the project-wide auth/tenant context — keeping the component dumb so
 * generated code stays portable across Next.js and plain Vite apps.
 */
export function PermitIssuanceStep(props: PermitIssuanceStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);

	const fire = React.useCallback(
		async (event: string) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, {});
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	return (
		<section data-testid="permit_issuance-step" aria-labelledby="permit_issuance-step-title">
			<header>
				<h2 id="permit_issuance-step-title">Issue the Building Permit Certificate</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<dl>
				{FIELDS.map((field) => (
					<React.Fragment key={field.id}>
						<dt>{field.label}{field.required ? " *" : ""}{field.pii ? " (PII)" : ""}</dt>
						<dd>—</dd>
					</React.Fragment>
				))}
			</dl>
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("submit")}>
					Submit
				</button>
				<button type="button" disabled={busy} onClick={() => fire("approve")}>
					Approve
				</button>
			</footer>
		</section>
	);
}
